var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"어라? 이 침묵은 설마……?","JPN":"あれ？　この沈黙はまさか……？","ENG":"Huh? This silence...","TWN":"咦？這段沉默難道……？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아하, 로터스 시니어님께서도 텔레파시 능력자인 겁니까?","JPN":"ははーん、ロータスのシニアさんもテレパシー能力者なんやな！","ENG":"A-ha, are you a telepath too, Senior of Lotus?","TWN":"啊哈，難道洛德斯的Senior也會心電感應嗎？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L8_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"누, 누가 텔레파시 능력자라는 거야?!","JPN":"だ、誰がテレパシー能力者だっていうのよ！","ENG":"W-who are you calling a telepath?!","TWN":"誰、誰會心電感應啊？！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그리고, 당신이 미리네인지 뭔지 무슨 상관인 건데?!","JPN":"あと、「ウチはオノデラ・マリや」ー？　だから何だって言うのよ！　いきなり現れて！","ENG":"And what does it matter if you're Mi Rinae or whatever?!","TWN":"還有誰管妳是不是叫宓璃奈？！"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아이고~","JPN":"いやぁ～","ENG":"Goodness.","TWN":"哎喲～"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"귀청 떨어지게 반응하는 걸 보니까, 성격 예민한 것도 딱 로터스의 시니어님이 맞네예.","JPN":"耳が痛いほどの返事を返すとことか、神経質そうなとこ見ると、ロータスのシニアさんに間違いないな。","ENG":"That eardrum-busting reaction fits the sensitive personality I heard about. You really are the Senior of Lotus.","TWN":"看你這反應這麼大，果然跟傳聞中的洛德斯Senior一樣性格很敏感。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"다시 소개할게요. 저는 쌤의 부탁을 받아서 여기 오게 된 미리네라 캅니다.","JPN":"改めて紹介させてもらうわ。ウチは先生に頼まれてここに来た、オノデラ・マリや。","ENG":"Lemme reintroduce myself. I'm Mi Rinae, here at Teach's request.","TWN":"我再自我介紹一次。我是受老師拜託，特地過來的宓璃奈。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"쌤……?","JPN":"先生……？","ENG":"Teach...?","TWN":"老師……？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"흥, 이 시간에 이렇게 찾아오는 사람이면 뻔하지.","JPN":"ふん、こんな時に突然やってくる人の正体なんて決まってる。","ENG":"Hmph, if someone shows up at this hour, isn't it obvious?","TWN":"哼，會在這種時間跑來的人不就只有那幾位嗎？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"최고 관리자의 지시야?","JPN":"最高管理者の指示なんでしょ？","ENG":"Orders from the Supreme Administrator?","TWN":"是最高管理者的指示吧？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"역시! 쌤이 천재라 카더니 눈치도 빠르시네요.","JPN":"さすが！　先生が天才ゆうてただけあって察しがええね。","ENG":"As expected. Teach said you were a genius, and you are quick on the uptake.","TWN":"果然！老師說妳是天才，果然連反應都很快呢。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"맞아요. 이제 막 아마니 밸리에 도착했는데 서둘러 여기로 가라 안 캅니까?","JPN":"そうや。アマニーバレーに着いたとこやのに、はよ行け言われて……ホンマかなんわ。","ENG":"Right. I'd just arrived at Amani Valley when I was told to hurry here.","TWN":"沒錯。我才剛到阿瑪尼山谷，就被要求立刻趕來這裡。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"자, 이거 받으세요.","JPN":"じゃ、これ受け取ってな。","ENG":"Here, take this.","TWN":"來，這個給你。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이, 이건……?","JPN":"こ、これは……？","ENG":"W-what is this...?","TWN":"這、這是……？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"황금 해골이로군요.","JPN":"黄金の骸骨ですね。","ENG":"A golden skull.","TWN":"是黃金骷髏呢。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그래서, 이게 뭔데?","JPN":"で、これがどうしたの？","ENG":"So what is it?","TWN":"所以這到底是什麼？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That's...","TWN":"那個是……"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그건 제가 설명해 드릴게요.","JPN":"それは私から説明します。","ENG":"\\"That, I'll explain.\\"","TWN":"由我來說明吧。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SERIOUS"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"제 이름은 시타 칸. 캄파멘토의 새로운 시니어예요.","JPN":"私の名前はシータ・カン。カンパメントの新しいシニアです。","ENG":"\\"My name is Sita Khan. I am the new Senior of Campamento.\\"","TWN":"我叫悉多坎，是坎帕門托的新任Senior。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SERIOUS"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"새로운 시니어라고?","JPN":"新しいシニア？","ENG":"The new Senior?","TWN":"新任Senior？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"잠깐, 그래서 둘 중 누가 시니어라는 거야?","JPN":"待って、シニアってどっち？","ENG":"Wait, which of you is the Senior then?","TWN":"等一下，所以這兩個人裡到底誰是Senior？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"왜 저 꼬마애가 말하면 당신이 이어받는 건데?","JPN":"なんで喋り始めたのはあの子なのに、続きはあなたが言うわけ？","ENG":"Why does the little one start talking and you finish for her?","TWN":"為什麼那小鬼說話後你就要接話？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"저, 저예요…….","JPN":"わ、私です……","ENG":"I-it is me...","TWN":"是、是我……。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"하아, 뭔가 따지기엔 시간이 촉박하니까 그냥 넘어가자.","JPN":"はあ……色々突っ込みたいけど時間がないからやめとくよ。","ENG":"*Sigh* We're short on time, so I'll let it slide.","TWN":"唉，現在時間太緊急，沒空計較了。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"그 황금 유해는…….","JPN":"その黄金の遺骸は……","ENG":"Those golden remains are...","TWN":"那黃金遺骸是……"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SERIOUS"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그 황금 유해는 할아버지께서 평생을 찾아 헤매던 황금향의 유산이에요.","JPN":"その黄金の遺骸は、おじいさまが生涯をかけて探した黄金郷の遺産なんです。","ENG":"\\"Those golden remains are the Golden Vale's Legacy my grandfather searched for all his life.\\"","TWN":"那黃金遺骸，是我爺爺畢生追尋的黃金鄉遺產。"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SERIOUS"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"할아버지라고? 설마 칸 할아버지가……?","JPN":"おじいさま？　まさか、カンじいさんが……？","ENG":"Your grandfather? Do you mean Grandpa Khan...?","TWN":"爺爺？難道說坎爺爺他……？"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"캄파멘토에서 무슨 일이 일어났냐면…….","JPN":"カンパメントで何が起きたかと言いますと……","ENG":"As for what happened in Campamento...","TWN":"坎帕門托發生的事是……"},"stage":{"bg":"CAMP_01","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"그…….","JPN":"と……","ENG":"Well...","TWN":"那個……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_CLOCK_02"},{"id":"L1_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그렇게 된 거예요.","JPN":"というわけです。","ENG":"That's how it went.","TWN":"就變成這樣了。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시, 실례지만 물 좀 마셔도 될까요?","JPN":"す、すみませんが、水を飲んでもいいでしょうか。","ENG":"E-excuse me, may I have some water?","TWN":"抱、抱歉，我能喝點水嗎……？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그렇구나… 칸 할아버지가…….","JPN":"そうか……あのカンじいさんが……","ENG":"I see... Grandpa Khan's...","TWN":"原來如此……坎爺爺他……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"지나치게 외향적인 사람이라 좀 부담스럽긴 했어도 정말 좋은 사람이었는데…….","JPN":"社交的すぎてちょっと苦手な部分はあったけど、本当にいい人だったのに……","ENG":"He was overly outgoing and a bit much at times, but he was truly a good person.","TWN":" 雖然他太外向讓人有點吃不消，但他人真的很好……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그럼 칸 할아버지가 찾아낸 그 유해가 공간을 안정시켜주는 아티팩트라는 말이지?","JPN":"じゃあ、カンじいさんが見つけたその遺骸が、空間を安定化させてくれるアーティファクトってわけ？","ENG":"So those remains he found are an Artifact that stabilizes space, right?","TWN":"所以坎爺爺找到的這個遺骸，是能讓空間穩來的古代遺物嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"네…….","JPN":"はい…","ENG":"Yes...","TWN":"對……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"하, 그 할아버지… 결국 상상 속에서나 존재하던 곳을 정말로 찾아내다니…….","JPN":"はあ、あの人……想像の中の場所を、本当に見つけ出しちゃったのね……","ENG":"*Sigh* So he actually found a place most thought existed only in imagination.","TWN":"哈，那位爺爺……居然真的找到了那只能存在於想像的地方……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"좋아.","JPN":"分かった。","ENG":"All right.","TWN":"很好。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그 멍청한 할아버지도 해냈는데, 나라고 못 해낼 건 없지.","JPN":"あの抜けてる人だってやってのけたのに、私にできないわけがない。","ENG":"If that foolish old man pulled it off, there is no reason I can't.","TWN":"既然那位傻爺爺都能做到了，我又怎麼會做不到？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"하아, 다행이다. 다들 무사했구나?","JPN":"はあ……よかった。皆無事だったのね。","ENG":"Whew, thank goodness. Everyone's safe.","TWN":"哈，太好了，大家都平安無事啊？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"알렉스 씨? 여긴 어쩐 일로……?","JPN":"アレックスさん？　どうしてここへ……？","ENG":"Alex? What brings you here?","TWN":"雅蕾克絲？妳怎麼會在這裡……？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"ARC-EX의 방위선은 어떻게 되었습니까?","JPN":"ARC-EXの防衛線はどうなりましたか？","ENG":"What about the defense line at ARC-EX?","TWN":"ARC-EX的防線情況如何？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"시민들이 모두 대피할 시간은 벌었어. 이터니움도 목표한 양만큼 회수했고.","JPN":"市民全員が避難できるぐらいの時間は稼げたわ。エタニウムも目標にしていた分は確保できた。","ENG":"We bought enough time for all citizens to evacuate, and we recovered the target amount of Eternium.","TWN":"我們爭取到讓市民撤離的時間，也回收目標數量的永恆之金了。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"하지만 마왕은 이 상황을 노린 것 같아.","JPN":"でも、魔王はこうなることを狙ってたみたい。","ENG":"But it seems the Demon Lord was aiming for this very situation.","TWN":"但魔王似乎覬覦著這個情況。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"재건 도시를 동시다발적으로 습격한 건 우리를 유인하기 위한 계획이었어.","JPN":"再建都市を同時多発的に襲撃したのは、私たちを誘導するための計画だったの。","ENG":"The simultaneous raids on the reconstruction cities were a plan to lure us away.","TWN":"牠同時襲擊各個重建城市，就是為了把我們引出來。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"우리가 방위선을 구축하리라 예상하고 미리 변수를 제거하려 했던 거야.","JPN":"私たちが防衛線を築くだろうと予測して、あらかじめ異変を起こし得る変数を排除するためにね。","ENG":"They predicted we would set up defense lines and tried to remove variables in advance.","TWN":"牠預料到我們會設置防線，提前清除變數清。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"……그래서 직할 도시를 향한 습격이 ARC-EX와 동시에 이루어진 것이군요.","JPN":"……それで、本来直轄都市に来るべきだった襲撃がARC-EXでも同時に行われたのですね。","ENG":"So the raid on the Direct Control City happened at the same time as ARC-EX.","TWN":"……所以才會同時襲擊直轄城市的與ARC-EX啊。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"하지만 습격은 어떻게든 막아냈습니다.","JPN":"ですが、襲撃は何とか止めました。","ENG":"We managed to repel it somehow.","TWN":"不過我們還是撐過襲擊了。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그렇다면 적의 계획을 저지한 게 아닌가요?","JPN":"これで敵の計画は阻止できたのではありませんか？","ENG":"Doesn't that mean we thwarted their plan?","TWN":"這樣不就阻止敵人的計畫了嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"분명 우리가 생각하지도 못할 무언가가 더 있을 거야.","JPN":"きっと、私たちがまだ気づいていない何かがあるはずよ。","ENG":"There must be something more that we haven't even considered.","TWN":"一定還有我們沒想到的東西。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"클리포트 게임의 규칙을 어길 만큼 확실한 목적이 있다면 더더욱.","JPN":"クリフォトゲームのルールを破るほどの明確な目的があるのなら、なおさらね。","ENG":"If they are willing to break the Qliphoth Game rules, their objective is very certain.","TWN":"能讓牠不惜違反逆卡巴拉遊戲規則的原因絕對不只如此。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"여, 여러분들! 큰일이에요!","JPN":"み、皆さん！　大変です！","ENG":"E-everyone, we have a problem!","TWN":"各、各位！不好了！"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_ON","text":{"KOREA":"대균열에서 나무뿌리 같은 게 빠져나오고 있어요!","JPN":"大亀裂から木の根みたいなものが出てきてます！","ENG":"Something like tree roots is coming out of the Grand Dimension Crevice!","TWN":"大峽谷冒出像樹根一樣的東西！"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"나무뿌리라고?","JPN":"木の根？","ENG":"Tree roots?","TWN":"樹根？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_ON","face":"UNIT_SERIOUS"},"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"하아, 결국 여기도 나타난기가?","JPN":"はあ、結局こっちにも現れたんか？","ENG":"*Sigh* So it finally showed up here too.","TWN":"哈，結果這裡也出現了嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"당신은 그게 뭔지 알고 있는 거야?","JPN":"あなたはそれが何か知っているの？","ENG":"Do you know what it is?","TWN":"妳知道那是什麼嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"내도 자세한 건 모른다.","JPN":"ウチも詳しいことは知らへん。","ENG":"I don't know the details.","TWN":"我也不清楚細節。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"저게 캄파멘토를 집어삼켰고, 침식 재난을 가속시킨 다는 것 정도만 파악하고 있지.","JPN":"把握してんのは、あれがカンパメントを襲ったゆうことと、侵食災害を加速させるゆうことぐらいや。","ENG":"I only know it swallowed Campamento and accelerated the Corruption Disaster.","TWN":"我只知道那東西吞噬了坎帕門托，也加快侵蝕災難的速度。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"다들 정신 단디 잡아라.","JPN":"みんな、気を引き締めなあかんで。","ENG":"Everyone, steel yourselves.","TWN":"大家打起精神。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"지금부터 나타나는 놈들은 보통 침식체가 아닐끼다.","JPN":"これから現れるやつらは、おそらく並みの侵食体やない。","ENG":"What appears from now on won't be ordinary C.O.s.","TWN":"從現在開始出現的傢伙，不是普通的侵蝕體。"},"stage":{"bg":"MAINSTREAM_124010","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};